#!/usr/bin/env node

/**
 * Test script to verify config save/load
 */

import ConfigManager from './src/config/ConfigManager.js';
import chalk from 'chalk';
import os from 'os';
import path from 'path';
import fs from 'fs/promises';

async function testConfig() {
  console.log(chalk.bold.cyan('\n=== Testing Config Manager ===\n'));

  const configManager = new ConfigManager();
  const configPath = path.join(os.homedir(), '.codestralrc.json');

  console.log(chalk.white('Expected config path:'), chalk.cyan(configPath));

  // Check if config file exists
  try {
    const stats = await fs.stat(configPath);
    console.log(chalk.green('✓ Config file exists'));
    console.log(chalk.gray(`  Size: ${stats.size} bytes`));
    console.log(chalk.gray(`  Modified: ${stats.mtime}`));

    // Read and display content
    const content = await fs.readFile(configPath, 'utf8');
    console.log(chalk.white('\nConfig file content:'));
    console.log(chalk.gray(content));

    // Try to load with ConfigManager
    console.log(chalk.white('\nLoading with ConfigManager...'));
    const config = await configManager.load();
    console.log(chalk.green('✓ Config loaded successfully'));
    console.log(chalk.white('API Key present:'), config.mistral.apiKey ? chalk.green('Yes') : chalk.red('No'));
    console.log(chalk.white('Model:'), chalk.cyan(config.mistral.model));
    console.log(chalk.white('Autonomy Mode:'), chalk.cyan(config.agent.autonomyMode));

  } catch (error) {
    if (error.code === 'ENOENT') {
      console.log(chalk.yellow('⚠ Config file does not exist'));
      console.log(chalk.gray('This is expected on first run'));
    } else {
      console.log(chalk.red('✗ Error:'), error.message);
    }
  }

  console.log(chalk.bold.cyan('\n=== Test Complete ===\n'));
}

testConfig().catch(console.error);
